(N'6', N'Women''s Basketball Semifinals Preview And Schedule', N'The highly anticipated semifinals are here.', CAST(N'2024-08-01T00:00:00.000' AS DateTime), N'The inaugural Olympic breaking competition kicked off in La Concorde on Friday. The women''s basketball semifinals are set to be a thrilling match-up between the top teams in the world...', N'Olympics', 3, 1, 1, 1, CAST(N'2024-08-01T00:00:00.000' AS DateTime), N'https://images.pexels.com/photos/1332237/pexels-photo-1332237.jpeg?auto=compress&cs=tinysrgb&w=1200', 350),

(N'7', N'Carlos Yulo wins historic gold for Philippines', N'A monumental achievement in gymnastics.', CAST(N'2024-08-02T00:00:00.000' AS DateTime), N'Carlos Yulo has made history by winning the gold medal in the men''s floor exercise. This marks the first-ever Olympic gymnastics medal for the Philippines...', N'Olympics', 4, 1, 1, 1, CAST(N'2024-08-02T00:00:00.000' AS DateTime), N'https://images.pexels.com/photos/163452/basketball-dunk-blue-game-163452.jpeg?auto=compress&cs=tinysrgb&w=1200', 420),

(N'8', N'Uzbekistan''s Rashitov defends Olympic men''s -68kg taekwondo title', N'A stunning display of martial arts mastery.', CAST(N'2024-08-03T00:00:00.000' AS DateTime), N'Ulugbek Rashitov of Uzbekistan successfully defended his Olympic title in the men''s -68kg taekwondo event. He defeated his opponents with precise strikes and unmatched agility...', N'Olympics', 5, 1, 2, 2, CAST(N'2024-08-03T00:00:00.000' AS DateTime), N'https://images.pexels.com/photos/7045748/pexels-photo-7045748.jpeg?auto=compress&cs=tinysrgb&w=1200', 120),

(N'9', N'The People''s Republic of China reigns supreme in men''s team', N'Dominance in table tennis continues.', CAST(N'2024-08-04T00:00:00.000' AS DateTime), N'The men''s table tennis team from the People''s Republic of China has once again proven their dominance. They swept through the competition to claim the gold medal without dropping a single match...', N'Olympics', 2, 1, 2, 2, CAST(N'2024-08-04T00:00:00.000' AS DateTime), N'https://images.pexels.com/photos/863988/pexels-photo-863988.jpeg?auto=compress&cs=tinysrgb&w=1200', 500),

(N'10', N'Curry shoots up France as Team USA takes another gold', N'A masterclass in three-point shooting.', CAST(N'2024-08-05T00:00:00.000' AS DateTime), N'Stephen Curry led Team USA to victory against France in the final match. His incredible performance, sinking consecutive three-pointers in the final quarter, secured another gold medal for the United States...', N'Olympics', 3, 1, 1, 1, CAST(N'2024-08-05T00:00:00.000' AS DateTime), N'https://images.pexels.com/photos/209977/pexels-photo-209977.jpeg?auto=compress&cs=tinysrgb&w=1200', 890);
